// Final Admin Timesheets report: period selector, user grouping, actual vs planned costing.
(function(){
  const esc=s=>String(s??'').replace(/[&<>"']/g,c=>({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[c]));
  const min=t=>{let p=String(t||'00:00').split(':').map(Number);return (p[0]||0)*60+(p[1]||0)};
  const span=s=>{let a=min(s.start),b=min(s.end);if(b<=a)b+=1440;return Math.max(0,b-a)};
  const log=id=>state.logs?.[id]||{in:null,out:null,breaks:[]};
  const bmins=(id,paid)=>{let l=log(id);return (l.breaks||[]).filter(b=>b.end&&(paid==null||b.paid===paid)).reduce((t,b)=>t+Math.max(0,Math.round((new Date(b.end)-new Date(b.start))/60000)),0)};
  const worked=s=>{let l=log(s.id);return !!(l.in&&l.out)};
  const paidMins=s=>{let l=log(s.id);let total=worked(s)?Math.max(0,Math.round((new Date(l.out)-new Date(l.in))/60000)):span(s);return Math.max(0,total-bmins(s.id,false))};
  const money=n=>'£'+Number(n||0).toFixed(2);
  const user=id=>(state.users||[]).find(u=>u.id===id);
  function cost(s){let u=user(s.userId);if(!u||s.userId==='unassigned')return 0;let h=paidMins(s)/60;if(u.payType==='salary'){let annual=Number(u.salaryAnnualAmount||u.wage||0);let hourly=annual/52/Math.max(1,Number(u.contractedHoursPerWeek||37.5));return h*hourly;}return h*Number(u.wage||0)}
  function range(){let mode=document.getElementById('tsMode')?.value||'week';let val=document.getElementById('tsPeriod')?.value;let now=new Date();let start,end;if(mode==='month'){let parts=(val||now.toISOString().slice(0,7)).split('-');start=new Date(Number(parts[0]),Number(parts[1])-1,1);end=new Date(Number(parts[0]),Number(parts[1]),0);}else if(mode==='year'){let y=Number(val||now.getFullYear());start=new Date(y,0,1);end=new Date(y,11,31);}else{let d=val?new Date(val+'T12:00:00'):monday(now);start=monday(d);end=plus(start,6);}return {mode,start:iso(start),end:iso(end)}}
  window.setTimesheetMode=function(){let mode=document.getElementById('tsMode').value;let p=document.getElementById('tsPeriod');let now=new Date();p.type=mode==='month'?'month':mode==='year'?'number':'date';p.value=mode==='month'?now.toISOString().slice(0,7):mode==='year'?String(now.getFullYear()):iso(monday(now));renderAdminTimesheetsFinal();}
  window.renderAdminTimesheetsFinal=function(){let r=range();let rows=(state.shifts||[]).filter(s=>s.date>=r.start&&s.date<=r.end).sort((a,b)=>String(a.userId).localeCompare(String(b.userId))||String(a.date).localeCompare(String(b.date))||String(a.start).localeCompare(String(b.start)));let by={};rows.forEach(s=>{let k=s.userId||'unassigned';(by[k]=by[k]||[]).push(s)});let html=`<h2>Timesheets</h2><div class="timesheetControls"><label>View<select id="tsMode" onchange="setTimesheetMode()"><option value="week" ${r.mode==='week'?'selected':''}>Week</option><option value="month" ${r.mode==='month'?'selected':''}>Month</option><option value="year" ${r.mode==='year'?'selected':''}>Year</option></select></label><label>Period<input id="tsPeriod" type="${r.mode==='month'?'month':r.mode==='year'?'number':'date'}" value="${r.mode==='month'?r.start.slice(0,7):r.mode==='year'?r.start.slice(0,4):r.start}" onchange="renderAdminTimesheetsFinal()"></label></div><p class="muted">Showing ${esc(r.start)} to ${esc(r.end)}. Completed shifts use actual clock times. Planned/scheduled shifts use estimated scheduled hours.</p>`;Object.keys(by).forEach(uid=>{let u=user(uid);let name=uid==='unassigned'||!u?'Unassigned':u.name;let total=by[uid].reduce((a,s)=>{a.h+=paidMins(s)/60;a.c+=cost(s);return a},{h:0,c:0});html+=`<section class="timesheetUserBlock"><h3>${esc(name)} <span>${total.h.toFixed(2)} hrs · ${money(total.c)}</span></h3><div class="tableWrap"><table><tr><th>Date</th><th>Shift</th><th>Area</th><th>Status</th><th>Payable hours</th><th>Cost</th></tr>${by[uid].map(s=>{let status=worked(s)?'Completed actual':(s.publishedAt?'Scheduled estimate':'Planned estimate');let actual=worked(s)?`${new Date(log(s.id).in).toLocaleTimeString('en-GB',{hour:'2-digit',minute:'2-digit'})}-${new Date(log(s.id).out).toLocaleTimeString('en-GB',{hour:'2-digit',minute:'2-digit'})}`:`${s.start}-${s.end}`;return `<tr><td>${esc(s.date)}</td><td>${esc(actual)}</td><td>${esc(s.section)}</td><td>${status}</td><td>${(paidMins(s)/60).toFixed(2)}</td><td>${money(cost(s))}</td></tr>`}).join('')}</table></div></section>`});document.getElementById('adminInner').innerHTML=html;}
  const oldDraw=window.drawAdmin||drawAdmin;
  window.drawAdmin=function(){oldDraw();if(state.adminPanel==='timesheets')renderAdminTimesheetsFinal();};
  drawAdmin=window.drawAdmin;
})();
